const items = $input.all();

const normalize = (s) =>
  String(s ?? "")
    .replace(/\r\n/g, "\n")
    .replace(/\r/g, "\n")
    .trim();

// vCard folded lines: newline + space/tab continues previous line
const unfold = (s) => s.replace(/\n[ \t]/g, "");

const pickFirst = (arr) => (arr && arr.length ? arr[0].value : "");

const hasParam = (entry, param) =>
  (entry.params || []).some((p) => String(p).toUpperCase() === param);

const pickTel = (telEntries, wantedParam) => {
  if (!telEntries?.length) return "";
  const found = telEntries.find((e) => hasParam(e, wantedParam));
  return found?.value || "";
};

const pickEmail = (emailEntries) => {
  if (!emailEntries?.length) return "";
  // prefer WORK if present, else first
  const work = emailEntries.find((e) => hasParam(e, "WORK"));
  return (work || emailEntries[0]).value || "";
};

return items.map((item) => {
  const body = item.json.body;

  // Most common shape (your screenshot): body is object and vCard is in body.code
  const vcardRaw =
    (typeof body === "object" && body?.code) ? body.code :
    (typeof body === "string") ? body :
    item.json.code || "";

  const vcard = unfold(normalize(vcardRaw));
  if (!vcard.startsWith("BEGIN:VCARD")) throw new Error("No vCard found in payload");

  // Parse into: { KEY: [ { params:[], value:"..." }, ... ] }
  const parsed = {};
  for (const line of vcard.split("\n")) {
    if (!line || line.startsWith("BEGIN:") || line.startsWith("END:") || line.startsWith("VERSION:")) continue;

    const idx = line.indexOf(":");
    if (idx === -1) continue;

    const left = line.slice(0, idx);
    const value = line.slice(idx + 1).trim();

    const parts = left.split(";");
    const key = parts[0].toUpperCase();
    const params = parts.slice(1).map((p) => String(p).toUpperCase());

    if (!parsed[key]) parsed[key] = [];
    parsed[key].push({ params, value });
  }

  // Name
  let firstName = "";
  let lastName = "";

  const nVal = pickFirst(parsed.N); // "Last;First;..."
  if (nVal) {
    const [ln = "", fn = ""] = nVal.split(";");
    firstName = fn;
    lastName = ln;
  } else {
    // fallback: split FN
    const fn = pickFirst(parsed.FN).trim();
    if (fn) {
      const seg = fn.split(/\s+/);
      if (seg.length >= 2) {
        lastName = seg.pop();
        firstName = seg.join(" ");
      } else {
        firstName = fn;
      }
    }
  }

  // Address (ADR: POBOX;EXT;STREET;CITY;REGION;POSTAL;COUNTRY)
  const adrVal = pickFirst(parsed.ADR);
  let street = "", city = "", state = "", zip = "", country = "";
  if (adrVal) {
    const adrParts = adrVal.split(";");
    street = adrParts[2] || "";
    city   = adrParts[3] || "";
    state  = adrParts[4] || "";
    zip    = adrParts[5] || "";
    country= adrParts[6] || "";
  }

  // Phones
  const tel = parsed.TEL || [];
  const mobile = pickTel(tel, "CELL") || pickTel(tel, "MOBILE");
  const fax = pickTel(tel, "FAX");
  const phone = pickTel(tel, "WORK") || pickTel(tel, "VOICE") || (tel[0]?.value || "");

  // Email / Company / Position / Website
  const email = pickEmail(parsed.EMAIL);
  const company = pickFirst(parsed.ORG);
  const position = pickFirst(parsed.TITLE);
  const website = pickFirst(parsed.URL);

  return {
    json: {
      firstName,
      lastName,
      email,
      mobile,
      fax,
      phone,
      company,
      position,
      street,
      city,
      state,
      country,
      zip,
      website,
    },
  };
});
